<?php
declare(strict_types=1);namespace App\Services;use App\Models\CommissionEntryModel;use App\Models\CommissionRuleModel;use RuntimeException;class CommissionService
{
 public function calculate():int{$db=db_connect();$rules=(new CommissionRuleModel())->where('is_active',1)->findAll();$created=0;foreach($rules as $rule){$documents=$db->table('sales_documents')->where('document_type','order')->whereIn('status',['approved','procurement_waiting','reserved','partially_shipped','shipped','delivered'])->where('created_at >=',$rule['starts_on'].' 00:00:00');if($rule['ends_on'])$documents->where('created_at <=',$rule['ends_on'].' 23:59:59');if($rule['employee_id'])$documents->where('sales_employee_id',$rule['employee_id']);foreach($documents->get()->getResultArray() as $document){if(!$document['sales_employee_id'])continue;$base=$this->base((int)$document['id'],$rule);if($base<=0)continue;$model=new CommissionEntryModel();$existing=$model->where(['commission_rule_id'=>$rule['id'],'sales_document_id'=>$document['id'],'sales_employee_id'=>$document['sales_employee_id']])->first();$status=in_array($document['status'],['shipped','delivered'],true)?'earned':'pending';if($existing){if($existing['status']==='pending'&&$status==='earned')$model->update($existing['id'],['status'=>'earned']);continue;}$amount=round($base*(float)$rule['rate_percent']/100,2);$model->insert(['commission_rule_id'=>$rule['id'],'sales_document_id'=>$document['id'],'sales_employee_id'=>$document['sales_employee_id'],'base_amount'=>$base,'rate_percent'=>$rule['rate_percent'],'commission_amount'=>$amount,'status'=>$status,'calculation_snapshot'=>json_encode(['rule'=>$rule['name'],'base_type'=>$rule['base_type'],'document'=>$document['document_number'],'calculated_at'=>date('c')],JSON_UNESCAPED_UNICODE)]);$created++;}}return$created;}
 private function base(int $documentId,array $rule):float{return$this->sumRows(db_connect(),$documentId,$rule);}
 private function sumRows($db,int $documentId,array $rule):float{$q=$db->table('sales_document_items sdi')->select('sdi.quantity,sdi.net_amount,COALESCE(pv.cost_price_override,p.cost_price) AS cost_price',false)->join('products p','p.id=sdi.product_id')->join('product_variants pv','pv.id=sdi.product_variant_id')->where('sdi.sales_document_id',$documentId);if($rule['product_category_id'])$q->where('p.category_id',$rule['product_category_id']);$sum=0.0;foreach($q->get()->getResultArray() as $row)$sum+=$rule['base_type']==='profit'?max(0,(float)$row['net_amount']-(float)$row['quantity']*(float)$row['cost_price']):(float)$row['net_amount'];return round($sum,2);}
}
